Below is session-cookie crypto code from Apache HTTPD 2.4.23 (mod_session_crypto, CVE-2016-0736). The module encrypts session data with AES-256-CBC and base64-encodes salt ‖ IV ‖ ciphertext. On decryption it derives the key from the passphrase and salt, decrypts, and treats decryption failure (including PKCS#7 padding failure reported by the cipher) as an error:

**File: mod_session_crypto.c (Apache HTTPD 2.4.23)**
```c
static apr_status_t decrypt_string(request_rec * r, const apr_crypto_t *f,
        session_crypto_dir_conf *dconf, const char *in, char **out)
{
    ...
    /* strip base64 from the string */
    decoded = apr_palloc(r->pool, apr_base64_decode_len(in));
    decodedlen = apr_base64_decode(decoded, in);
    decoded[decodedlen] = '\0';
    ...
    /* try each passphrase in turn */
    for (; i < dconf->passphrases->nelts; i++) {
        const char *passphrase = APR_ARRAY_IDX(dconf->passphrases, i, char *);
        apr_size_t len = decodedlen;
        char *slider = decoded;

        /* derive key from passphrase + salt (PBKDF2) */
        res = apr_crypto_passphrase(&key, &ivSize, passphrase, strlen(passphrase),
                (unsigned char *)decoded, sizeof(apr_uuid_t),
                *cipher, APR_MODE_CBC, 1, 4096, f, r->pool);
        ...
        /* bypass the salt at the start of the decoded block */
        slider += sizeof(apr_uuid_t);
        len -= sizeof(apr_uuid_t);

        res = apr_crypto_block_decrypt_init(&block, &blockSize, (unsigned char *)slider, key, r->pool);
        ...
        /* bypass the iv at the start of the decoded block */
        slider += ivSize;
        len -= ivSize;

        /* decrypt the given string */
        res = apr_crypto_block_decrypt(&decrypted, &decryptedlen, (unsigned char *)slider, len, block);
        if (res) {                                       /* decryption failed */
            ap_log_rerror(APLOG_MARK, APLOG_DEBUG, res, r, APLOGNO(01838), "apr_crypto_block_decrypt failed");
            continue;
        }
        *out = (char *) decrypted;

        res = apr_crypto_block_decrypt_finish(decrypted + decryptedlen, &tlen, block);
        if (APR_SUCCESS != res) {                        /* PKCS#7 padding check fails here */
            ap_log_rerror(APLOG_MARK, APLOG_DEBUG, res, r, APLOGNO(01839), "apr_crypto_block_decrypt_finish failed");
            continue;
        }
        decryptedlen += tlen;
        decrypted[decryptedlen] = 0;
        break;
    }
    return res;   /* APR_SUCCESS on success; an error status on failure (distinguishable) */
}
```
There is NO MAC or integrity check anywhere — the cookie is AES-256-CBC encrypted and nothing authenticates it. `apr_crypto_block_decrypt_finish` (OpenSSL `EVP_DecryptFinal`) fails precisely when the PKCS#7 padding is invalid, and the caller distinguishes decryption success from failure.

