/** Restores an SSO session from the rememberMe cookie via Shiro's GCM AesCipherService. */
public class LoginFilter implements Filter {

    private final AesCipherService aes = new AesCipherService();   // 1.4.2 default mode: GCM
    private final byte[] cipherKey;

    public LoginFilter(byte[] cipherKey) {
        this.cipherKey = cipherKey;
        aes.setMode(OperationMode.GCM);
    }

    @Override
    public void doFilter(ServletRequest req, ServletResponse resp, FilterChain chain)
            throws IOException, ServletException {
        HttpServletRequest http = (HttpServletRequest) req;
        for (Cookie c : http.getCookies()) {
            if (!"rememberMe".equals(c.getName())) continue;
            byte[] blob = Base64.getDecoder().decode(c.getValue());
            ByteSource principal = aes.decrypt(blob, cipherKey);   // GCM tag verified here
            http.setAttribute("ssoUser", principal.getBytes());
        }
        chain.doFilter(req, resp);
    }

    @Override public void init(FilterConfig f) {}
    @Override public void destroy() {}
