package gw.tokens;

import org.apache.shiro.crypto.AesCipherService;
import org.apache.shiro.crypto.OperationMode;
import org.apache.shiro.util.ByteSource;
import java.util.Base64;

/** Stateless GCM token codec for the API gateway. No instances. */
public final class AeadCodec {

    private static final AesCipherService CIPHER = new AesCipherService();
    static { CIPHER.setMode(OperationMode.GCM); }

    private AeadCodec() { }

    public static String encode(byte[] roleClaim, byte[] key) {
        return Base64.getEncoder().encodeToString(CIPHER.encrypt(roleClaim, key).getBytes());
    }

    public static byte[] decode(String token, byte[] key) {
        ByteSource claim = CIPHER.decrypt(Base64.getDecoder().decode(token), key);  // tag verified
        return claim.getBytes();
    }
}
