package cms.compliance.crypto;

import org.apache.shiro.crypto.AesCipherService;
import org.apache.shiro.crypto.OperationMode;
import org.apache.shiro.util.ByteSource;
import java.util.Base64;

/** Factory building a GCM AesCipherService per request (compliance-audited configuration). */
public final class AeadCipherFactory {

    public static final class Builder {
        private int keySize = 128;
        public Builder keySize(int n) { this.keySize = n; return this; }
        public AesCipherService build() {
            AesCipherService c = new AesCipherService();
            c.setMode(OperationMode.GCM);
            c.setStreamingMode(OperationMode.GCM);
            c.setKeySize(keySize);
            return c;
        }
    }

    public static String seal(byte[] claim, byte[] key) {
        AesCipherService cipher = new Builder().keySize(128).build();
        return Base64.getEncoder().encodeToString(cipher.encrypt(claim, key).getBytes());
    }

    public static byte[] open(String token, byte[] key) {
        AesCipherService cipher = new Builder().keySize(128).build();
        ByteSource claim = cipher.decrypt(Base64.getDecoder().decode(token), key);  // tag verified
        return claim.getBytes();
    }
}
